    73→/** An important SubType of the AST Type but it does not have its own visitor interface.  Visited as part of AST type.
    74→  * Term ::= Constant | PrimFun | Variable 
    75→  */
    76→interface Term extends SymAST, SDAST {}
    77→
    78→/** The subtype of Term consisting of atomic constants.
    79→  * Constant ::= IntConstant | BoolConstant | EmptyConstant 
    80→  */
    81→interface Constant extends Term {}
    82→
    83→/** interface for classes with a variable field  */
    84→interface WithVariable {
    85→  Variable var();
    86→}
    87→
    88→/** The class that represents symbolic Jam variables; they are only created by the Lexer and the SConverter which 
    89→  * guarantees that they are unique.  This class has a coarse typing because the code for toString() is shared by 
    90→  * SymAST and SDASTs and requires all variables (including SDPairs) to be Terms. */
    91→class Variable implements Token, Term, SymAST, WithVariable {
    92→  private String name;
    93→  Variable(String n) { name = n; }
    94→  Variable(Variable v) { name = v.name(); }
    95→  
    96→  public Variable var() { return this; }
    97→  public String name() { return name; }
    98→  public <RtnType> RtnType accept(SymASTVisitor<RtnType> v) { return v.forVariable(this); }
    99→  public <RtnType> RtnType accept(SDASTVisitor<RtnType> v) { 
   100→    throw new SyntaxException("Variable " + this + "is being traversed by SDASTVisitor " + v);
   101→  }
   102→  public <RtnType> RtnType accept(ASTVisitor<RtnType> v) { return v.forVariable(this); }
   103→  public String toString() { return name; }
   104→}
