    47→/** Jam closure representation for programs with static distance coordinates */
    48→class SDClosure extends JamFun implements Closure {
    49→  private SMap smap;
    50→  private SDEvaluator eval;
    51→  SDClosure(SMap sm, SDEvaluator e) { smap = sm; eval = e; }
    52→  public int arity() { return smap.arity(); }
    53→  public JamVal apply(JamVal[] args) {
    54→    SDEnv newEnv = eval.env();
    55→    int n = smap.arity();
    56→    if (n != args.length) throw new EvalException("closure " + this + " applied to " + 
    57→       args.length + " arguments instead of " + n + " arguments");
    58→      newEnv = newEnv.cons(args);
    59→    return smap.body().accept((SDASTVisitor<JamVal>) eval.newEvalVisitor(newEnv));
    60→  }                                                 
    61→  public <RtnType> RtnType accept(FunVisitor<RtnType> jfv) { return jfv.forClosure(this); }
    62→  public String toString() { return "SDClosure<" + smap + ">"; }
    63→}
