    65→class Interpreter {
    66→  
    67→  /** Primary fields */
    68→  private Parser parser;
    69→  private SConverter sConverter;
    70→  
    71→  Interpreter(Parser p) { 
    72→    parser = p;
    73→    sConverter = p.sConverter();
    74→  }
    75→  Interpreter(String fileName) throws IOException { this(new Parser(fileName)); }
    76→  Interpreter(Reader reader) { this(new Parser(reader)); }
    77→    
    78→    /** Parses, checks, and interprets the input embeded in parser */
    79→    public JamVal eval() {
    80→    SymAST prog = parser.checkProg();
    81→    return prog.accept(valueValueVisitor); 
    82→  }
    83→  
    84→  /** Parses and checks the input embeded in parser, converts it to SD form, and interprets it. */
    85→  public JamVal SDEval() {
    86→    SDAST prog = parser.statCheckProg();
    87→    return prog.accept(SDEvalVisitor); 
    88→  }
    89→  /** Parses, checks, CPS converts, and interprets the input embedded in parser using the SymAST representation. */
    90→  public JamVal cpsEval() {
    91→    SymAST prog = parser.cpsProg();
    92→    return prog.accept(valueValueVisitor);
    93→  }
    94→  /** Parses, checks, CPS converts, SD converts, and interprets the input embedded in parser using the SDAST representation. */
    95→  public JamVal SDCpsEval() {
    96→    SDAST prog = parser.statCpsProg();
    97→    return prog.accept(SDEvalVisitor);
    98→  }
