   103→    return prog;
   104→  }
   105→  
   106→  /** Returns the CPS form of the embedded proggram. */
   107→  public SymAST convertToCPS() { return parser.cpsProg(); }
   108→  
   109→  /** Returns the SDAST for the embedded program. */
   110→  public SDAST convertToSD() { 
