   446→    /* Extract binding vars and exps (rhs's) from l */
   447→    Variable[] vars = l.vars();
   448→    SymAST[] exps = l.exps();
   449→    int n = vars.length;
   450→    /* Construct newEnv for Let body and exps; vars are bound to values of corresponding exps using newEvalVisitor */
   451→    VarEnv newEnv = env();
   452→    Binding[] bindings = new Binding[n];
   453→    for (int i = n-1; i >= 0; i--) {
   454→      bindings[i] = new Binding(vars[i], exps[i].accept(this));  // bind var[i] to exps[i] in this evaluator
   455→      newEnv = newEnv.cons(bindings[i]);          
