   467→    VarEnv newEnv = env();
   468→    
   469→    Binding[] bindings = new Binding[n];
   470→    for (int i = n-1; i >= 0; i--) {
   471→      bindings[i] = new Binding(vars[i], null);  // bind var[i], setting value to null, which is not a JamVal
   472→      newEnv = newEnv.cons(bindings[i]);          
   473→    }
   474→    
   475→    SymASTVisitor<JamVal> newEvalVisitor = newEvalVisitor(newEnv);
